import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Download, Trash2, User } from 'lucide-react';
import { reportsApi } from '../api/reports';
import { exportApi } from '../api/export';
import DataTable from '../components/DataTable';
import MonthFilter from '../components/MonthFilter';
import FileImport from '../components/FileImport';
import Card from '../components/Card';
import StrategyViewInterface from '../components/StrategyViewInterface';
import ContentManagement from '../components/ContentManagement';
import { useClient } from '../contexts/ClientContext';
import { tiktokApi } from '../api/tiktok';
import { metaApi } from '../api/meta';

const Labs: React.FC = () => {
  const { selectedClient } = useClient();
  const [activeTab, setActiveTab] = useState<'data' | 'strategy' | 'content' | 'social'>('data');
  const [selectedMonth, setSelectedMonth] = useState('');
  const [tiktokConnected, setTiktokConnected] = useState(false);

  // Listen for TikTok auth success messages from popup
  React.useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data?.type === 'TIKTOK_AUTH_SUCCESS') {
        setTiktokConnected(true);
        console.log('TikTok connected successfully!');
        // You could also trigger a refetch of connection status here
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  // Check TikTok connection status when client changes
  React.useEffect(() => {
    if (selectedClient) {
      tiktokApi.getAccounts(selectedClient.id)
        .then(response => {
          setTiktokConnected(response.connected);
        })
        .catch(error => {
          console.error('Error checking TikTok connection:', error);
          setTiktokConnected(false);
        });
    }
  }, [selectedClient]);

  const handleTikTokConnect = () => {
    if (tiktokConnected) {
      // Handle disconnect
      setTiktokConnected(false);
      return;
    }

    const authUrl = `https://business-api.tiktok.com/portal/auth?app_id=7522384605962469377&state=${selectedClient?.id || 'default'}&redirect_uri=${encodeURIComponent('http://localhost:3000/tiktok-auth-callback')}`;
    const popup = window.open(authUrl, 'tiktok-auth', 'width=600,height=700,scrollbars=yes,resizable=yes');
    
    // Check if popup was blocked
    if (!popup) {
      alert('Popup was blocked. Please allow popups for this site and try again.');
    }
  };

  const { data: reports = [], isLoading: reportsLoading } = useQuery({
    queryKey: ['reports', selectedClient?.id, selectedMonth],
    queryFn: () => {
      if (!selectedClient) return Promise.resolve([]);
      return reportsApi.getReports({
        ...(selectedMonth ? { month: selectedMonth } : {}),
        clientId: selectedClient.id
      });
    },
    enabled: !!selectedClient,
  });

  // Extract unique months from reports
  const availableMonths = React.useMemo(() => {
    const months = new Set<string>();
    reports.forEach(report => {
      const date = new Date(report.report_date);
      const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
      months.add(monthKey);
    });
    return Array.from(months).sort().reverse();
  }, [reports]);

  const handleClearAll = () => {
    const confirmed = window.confirm(
      `Are you sure you want to clear all data for ${selectedClient?.name}? This action cannot be undone.`
    );
    if (confirmed) {
      // Handle clear all for specific client - would need mutation here
      console.log('Clear all data for client:', selectedClient?.id);
      // TODO: Implement client-specific clear mutation
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <h1 className="text-2xl font-bold text-gray-900 mb-8">Action Labs</h1>

      {!selectedClient ? (
        <Card>
          <div className="text-center py-12">
            <div className="w-16 h-16 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
              <User className="w-8 h-8 text-gray-400" />
            </div>
            <h3 className="text-lg font-medium text-gray-900 mb-2">
              Client Selection Required
            </h3>
            <p className="text-gray-600">
              Please select a client from the home page to access Action Labs features.
            </p>
          </div>
        </Card>
      ) : (
        <>
          {/* Tab Navigation */}
          <div className="border-b border-gray-200 mb-8">
            <nav className="-mb-px flex space-x-8">
              <button
                onClick={() => setActiveTab('data')}
                className={`py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'data'
                    ? 'border-primary-500 text-primary-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Data Entry
              </button>
              <button
                onClick={() => setActiveTab('strategy')}
                className={`py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'strategy'
                    ? 'border-primary-500 text-primary-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Strategy View
              </button>
              <button
                onClick={() => setActiveTab('content')}
                className={`py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'content'
                    ? 'border-primary-500 text-primary-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Content
              </button>
              <button
                onClick={() => setActiveTab('social')}
                className={`py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'social'
                    ? 'border-primary-500 text-primary-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Social Media
              </button>
            </nav>
          </div>

          {/* Data Entry Tab */}
          {activeTab === 'data' && (
            <div className="space-y-6">
              {/* Header Actions */}
              <Card>
                <div className="flex flex-wrap items-center justify-between gap-4">
                  <div>
                    <h2 className="text-lg font-semibold text-gray-900">Data Management</h2>
                    <p className="text-sm text-gray-600 mt-1">
                      Managing data for {selectedClient.name}
                    </p>
                  </div>
                  
                  <div className="flex flex-wrap items-center gap-4">
                    <FileImport />
                    
                    <a
                      href={`${exportApi.exportCsv()}?clientId=${selectedClient.id}`}
                      className="btn-secondary inline-flex items-center"
                    >
                      <Download className="w-4 h-4 mr-2" />
                      Export CSV
                    </a>
                    
                    <button
                      onClick={handleClearAll}
                      className="btn-danger inline-flex items-center"
                    >
                      <Trash2 className="w-4 h-4 mr-2" />
                      Clear All Data
                    </button>
                  </div>
                </div>
              </Card>

              {/* Controls */}
              <Card>
                <div className="flex items-center justify-between">
                  <MonthFilter
                    value={selectedMonth}
                    onChange={setSelectedMonth}
                    months={availableMonths}
                    loading={reportsLoading}
                  />
                  
                  <div className="text-sm text-gray-600">
                    {reports.length} record{reports.length !== 1 ? 's' : ''} found for {selectedClient.name}
                  </div>
                </div>
              </Card>

              {/* Data Table */}
              <DataTable
                data={reports}
                loading={reportsLoading}
                onView={(report) => {
                  alert(JSON.stringify(report, null, 2));
                }}
                onEdit={(report) => {
                  console.log('Edit report:', report);
                  // Would open edit modal here
                }}
              />
            </div>
          )}

          {/* Strategy View Tab */}
          {activeTab === 'strategy' && (
            <StrategyViewInterface />
          )}

          {/* Content Management Tab */}
          {activeTab === 'content' && (
            <ContentManagement />
          )}

          {/* Social Media Tab */}
          {activeTab === 'social' && (
            <div className="space-y-6">
              <Card>
                <div className="text-center py-12">
                  <div className="w-16 h-16 mx-auto mb-4 bg-gradient-to-br from-pink-400 to-purple-600 rounded-full flex items-center justify-center">
                    <svg className="w-8 h-8 text-white" fill="currentColor" viewBox="0 0 24 24">
                      <path d="M24 4.557c-.883.392-1.832.656-2.828.775 1.017-.609 1.798-1.574 2.165-2.724-.951.564-2.005.974-3.127 1.195-.897-.957-2.178-1.555-3.594-1.555-3.179 0-5.515 2.966-4.797 6.045-4.091-.205-7.719-2.165-10.148-5.144-1.29 2.213-.669 5.108 1.523 6.574-.806-.026-1.566-.247-2.229-.616-.054 2.281 1.581 4.415 3.949 4.89-.693.188-1.452.232-2.224.084.626 1.956 2.444 3.379 4.6 3.419-2.07 1.623-4.678 2.348-7.29 2.04 2.179 1.397 4.768 2.212 7.548 2.212 9.142 0 14.307-7.721 13.995-14.646.962-.695 1.797-1.562 2.457-2.549z"/>
                    </svg>
                  </div>
                  <h3 className="text-lg font-medium text-gray-900 mb-2">
                    Social Media Management
                  </h3>
                  <p className="text-gray-600 mb-6">
                    Manage social media content, campaigns, and analytics for {selectedClient?.name}.
                  </p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-w-2xl mx-auto">
                    {/* Meta (Facebook/Instagram) Connection */}
                    <div className="bg-white border-2 border-dashed border-gray-300 rounded-lg p-6 hover:border-gray-400 transition-colors">
                      <div className="text-center">
                        <div className="w-12 h-12 mx-auto mb-3 bg-gradient-to-br from-blue-600 to-pink-500 rounded-lg flex items-center justify-center">
                          <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 24 24">
                            <path d="M12 2.04c-5.5 0-9.96 4.46-9.96 9.96 0 5.5 4.46 9.96 9.96 9.96 5.5 0 9.96-4.46 9.96-9.96 0-5.5-4.46-9.96-9.96-9.96zm0 18.12c-4.5 0-8.16-3.66-8.16-8.16s3.66-8.16 8.16-8.16 8.16 3.66 8.16 8.16-3.66 8.16-8.16 8.16zm2.5-10.62c-.41 0-.75.34-.75.75v2.25c0 .41.34.75.75.75s.75-.34.75-.75v-2.25c0-.41-.34-.75-.75-.75zm-5 0c-.41 0-.75.34-.75.75v2.25c0 .41.34.75.75.75s.75-.34.75-.75v-2.25c0-.41-.34-.75-.75-.75z"/>
                          </svg>
                        </div>
                        <h4 className="font-medium text-gray-900 mb-1">Meta (Facebook/Instagram)</h4>
                        <p className="text-sm text-gray-500">Connect your Meta Business account for Facebook & Instagram management</p>
                        <button className="mt-3 px-4 py-2 text-sm font-medium rounded-md bg-blue-600 text-white hover:bg-blue-700 transition-colors">
                          Connect Meta
                        </button>
                      </div>
                    </div>
                    {/* TikTok Connection */}
                    <div className="bg-white border-2 border-dashed border-gray-300 rounded-lg p-6 hover:border-gray-400 transition-colors">
                      <div className="text-center">
                        <div className={`w-12 h-12 mx-auto mb-3 rounded-lg flex items-center justify-center ${tiktokConnected ? 'bg-green-100' : 'bg-black'}`}> 
                          {tiktokConnected ? (
                            <svg className="w-6 h-6 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                            </svg>
                          ) : (
                            <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 24 24">
                              <path d="M12.53.02C13.84 0 15.14.01 16.44 0c.08 1.53.63 3.09 1.75 4.17 1.12 1.11 2.7 1.62 4.24 1.79v4.03c-1.44-.05-2.89-.35-4.2-.97-.57-.26-1.1-.59-1.62-.93-.01 2.92.01 5.84-.02 8.75-.08 1.4-.54 2.79-1.35 3.94-1.31 1.92-3.58 3.17-5.91 3.21-1.43.08-2.86-.31-4.08-1.03-2.02-1.19-3.44-3.37-3.65-5.71-.02-.5-.03-1-.01-1.49.18-1.9 1.12-3.72 2.58-4.96 1.66-1.44 3.98-2.13 6.15-1.72.02 1.48-.04 2.96-.04 4.44-.99-.32-2.15-.23-3.02.37-.63.41-1.11 1.04-1.36 1.75-.21.51-.15 1.07-.14 1.61.24 1.64 1.82 3.02 3.5 2.87 1.12-.01 2.19-.66 2.77-1.61.19-.33.4-.67.41-1.06.1-1.79.06-3.57.07-5.36.01-4.03-.01-8.05.02-12.07z"/>
                            </svg>
                          )}
                        </div>
                        <h4 className="font-medium text-gray-900 mb-1">TikTok</h4>
                        <p className="text-sm text-gray-500">
                          {tiktokConnected ? 'Connected to TikTok Business' : 'Short-form video content and ads'}
                        </p>
                        <button 
                          onClick={handleTikTokConnect}
                          className={`mt-3 px-4 py-2 text-sm font-medium rounded-md transition-colors ${
                            tiktokConnected 
                              ? 'bg-red-600 text-white hover:bg-red-700' 
                              : 'bg-black text-white hover:bg-gray-800'
                          }`}
                        >
                          {tiktokConnected ? 'Disconnect' : 'Connect TikTok'}
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              </Card>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default Labs;
